// в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
//  Smartory вЂ” Order Service
//  Fetches smart shopping plans (order lists)
//  generated by the planner agent.
// в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

import Constants from "expo-constants";

const BASE_URL = Constants.expoConfig?.extra?.baseUrl;

// в”Ђв”Ђв”Ђ Types в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

export type OrderItem = {
  item: string;
  reason: string;
  have_ordered: boolean;
};

export type Order = {
  id: string;
  user_id: string;
  order: OrderItem[];
  created_at: string;
  estimated_date_to_order: string;
  is_complete: boolean;
};

export type IncompleteOrdersResponse = {
  status: "success" | "error";
  data: Order[];
};

// в”Ђв”Ђв”Ђ API calls в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Fetches all open (incomplete) order plans for the authenticated user.
 */
export async function fetchIncompleteOrders(
  token: string,
): Promise<IncompleteOrdersResponse> {
  const response = await fetch(`${BASE_URL}/orders/incomplete`, {
    method: "GET",
    headers: {
      accept: "application/json",
      Authorization: `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    const text = await response.text().catch(() => "");
    throw new Error(
      `Failed to fetch orders: HTTP ${response.status}${text ? ` вЂ” ${text}` : ""}`,
    );
  }

  return response.json() as Promise<IncompleteOrdersResponse>;
}

// в”Ђв”Ђв”Ђ Add item to order в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

export type AddItemResponse = {
  status: "success" | "error";
  data: Order;
};

/**
 * Manually adds a single item by name to an existing order plan.
 */
export async function addItemToOrder(
  token: string,
  orderId: string,
  itemName: string,
): Promise<AddItemResponse> {
  const response = await fetch(`${BASE_URL}/orders/${orderId}/items`, {
    method: "POST",
    headers: {
      accept: "application/json",
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ item_name: itemName }),
  });

  if (!response.ok) {
    const text = await response.text().catch(() => "");
    throw new Error(
      `Failed to add item: HTTP ${response.status}${text ? ` вЂ” ${text}` : ""}`,
    );
  }

  return response.json() as Promise<AddItemResponse>;
}

// в”Ђв”Ђв”Ђ Mark order complete / incomplete в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Marks an order plan as complete (or incomplete).
 */
export async function completePlan(
  token: string,
  orderId: string,
  isComplete = true,
): Promise<AddItemResponse> {
  const response = await fetch(`${BASE_URL}/orders/${orderId}`, {
    method: "PATCH",
    headers: {
      accept: "application/json",
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ is_complete: isComplete }),
  });

  if (!response.ok) {
    const text = await response.text().catch(() => "");
    throw new Error(
      `Failed to complete order: HTTP ${response.status}${text ? ` вЂ” ${text}` : ""}`,
    );
  }

  return response.json() as Promise<AddItemResponse>;
}

/**
 * Toggles have_ordered for an item by name inside an order plan.
 */
export async function togglePlanItem(
  token: string,
  orderId: string,
  itemName: string,
): Promise<AddItemResponse> {
  const response = await fetch(`${BASE_URL}/orders/${orderId}/items`, {
    method: "PATCH",
    headers: {
      accept: "application/json",
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ item_name: itemName }),
  });

  if (!response.ok) {
    const text = await response.text().catch(() => "");
    throw new Error(
      `Failed to toggle item: HTTP ${response.status}${text ? ` вЂ” ${text}` : ""}`,
    );
  }

  return response.json() as Promise<AddItemResponse>;
}
